import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useCart } from '../context/CartContext';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const { addToCart } = useCart();

  useEffect(() => {
    fetchFeaturedProducts();
  }, []);

  const fetchFeaturedProducts = async () => {
    try {
      const response = await axios.get('/api/products?category=all');
      // Get first 4 products as featured
      setFeaturedProducts(response.data.slice(0, 4));
    } catch (error) {
      console.error('Error fetching products:', error);
    }
  };

  const handleAddToCart = async (product) => {
    const result = await addToCart(product);
    if (result.success) {
      alert(`✓ "${product.name}" added to cart`);
    }
  };

  return (
    <>
      {/* Hero Section */}
      <section className="hero" aria-label="Hero banner">
        <div className="hero-content container">
          <div className="hero-badge">✦ New Season Collection</div>
          <h1>Discover <em>Premium</em> Style & Living</h1>
          <p>Curated collections of the world's finest products — delivered to your door with next-day shipping.</p>
          <div className="hero-actions">
            <Link to="/products" className="btn btn-primary">Shop Now ›</Link>
            <a href="#featured" className="btn btn-outline">View Collections</a>
          </div>
          <div className="hero-stats">
            <div className="stat-item">
              <span className="stat-number">10K+</span>
              <span className="stat-label">Products</span>
            </div>
            <div className="stat-item">
              <span className="stat-number">50K+</span>
              <span className="stat-label">Customers</span>
            </div>
            <div className="stat-item">
              <span className="stat-number">4.9★</span>
              <span className="stat-label">Rating</span>
            </div>
          </div>
        </div>
        <div className="hero-visual" aria-hidden="true">
          <div className="hero-bg-pattern"></div>
          <div className="hero-grid"></div>
        </div>
      </section>

      {/* Categories */}
      <section className="section bg-cream" id="categories" aria-label="Shop categories">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Browse by Category</span>
            <h2>What Are You Looking For?</h2>
          </div>
          <div className="categories-grid">
            <Link to="/products?cat=electronics" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">📱</span>
              <span>Electronics</span>
            </Link>
            <Link to="/products?cat=fashion" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">👗</span>
              <span>Fashion</span>
            </Link>
            <Link to="/products?cat=home" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">🏡</span>
              <span>Home</span>
            </Link>
            <Link to="/products?cat=beauty" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">💄</span>
              <span>Beauty</span>
            </Link>
            <Link to="/products?cat=sports" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">⚽</span>
              <span>Sports</span>
            </Link>
          </div>
        </div>
      </section>

      {/* Featured Products */}
      <section className="section" id="featured" aria-label="Featured products">
        <div className="container">
          <div className="section-header section-header-flex">
            <div>
              <span className="section-tag">Handpicked for You</span>
              <h2>Featured Products</h2>
            </div>
            <Link to="/products" className="btn btn-outline btn-sm">View All ›</Link>
          </div>
          <div className="products-grid">
            {featuredProducts.map(product => (
              <ProductCard 
                key={product._id} 
                product={product} 
                onAddToCart={handleAddToCart}
              />
            ))}
          </div>
        </div>
      </section>

      {/* Promo Banner */}
      <section className="promo-banner" aria-label="Promotional offer">
        <div className="container promo-content">
          <span className="section-tag section-tag-gold">Limited Time</span>
          <h2>Get 20% Off Your First Order</h2>
          <p>Use the code below at checkout. Valid for new customers only.</p>
          <div className="promo-code">
            <span>NOVA20</span>
            <button className="copy-btn" onClick={() => {
              navigator.clipboard.writeText('NOVA20');
              alert('Code copied to clipboard!');
            }}>Copy</button>
          </div>
          <Link to="/products" className="btn btn-gold">Shop the Sale ›</Link>
        </div>
      </section>

      {/* Trust Signals */}
      <section className="section bg-cream" aria-label="Why choose us">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Why Nova Shop</span>
            <h2>Shopping Made Simple</h2>
          </div>
          <div className="trust-grid">
            <div className="trust-card">
              <div className="trust-card__icon">🚚</div>
              <h4>Free Delivery</h4>
              <p>On orders over £50. Next-day available.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">🔒</div>
              <h4>Secure Payments</h4>
              <p>SSL encrypted. Pay with card, PayPal & more.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">↩️</div>
              <h4>Easy Returns</h4>
              <p>30-day hassle-free returns policy.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">💬</div>
              <h4>24/7 Support</h4>
              <p>Live chat, email or phone — always here.</p>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Home;
